# خوارزمية ميزان للتقطيع العروضي الذكي
class MizanAnalyzer:
    def __init__(self, verse):
        self.verse = verse
        self.prosodic_writing = ""
        self.binary_code = ""

    def convert_to_prosodic(self):
        # 1. [span_1](start_span)تطبيق قاعدة: "كل ما ينطق يكتب وكل ما لا ينطق لا يكتب"[span_1](end_span)
        # تشمل: فك التضعيف، إضافة التنوين كـ "ن"، حذف همزة الوصل... إلخ
        self.prosodic_writing = apply_khalil_rules(self.verse)
        return self.prosodic_writing

    def generate_binary(self):
        # 2. [span_2](start_span)تحويل النص إلى رموز حركية وسكونية (/ 0)[span_2](end_span)
        for char in self.prosodic_writing:
            if is_vowel(char):
                self.binary_code += "/"
            elif is_silent(char):
                self.binary_code += "0"
        return self.binary_code

    def detect_meter(self):
        # 3. [span_3](start_span)مقارنة الرمز الثنائي بقاعدة بيانات البحور الستة عشر[span_3](end_span)
        meter = match_with_khalil_meters(self.binary_code)
        return meter

