import React from 'react';
import ReactDOM from 'react-dom/client';
import App from './App';

const rootElement = document.getElementById('root');
if (!rootElement) {
  throw new Error("Could not find root element to mount to");
}

const root = ReactDOM.createRoot(rootElement);
root.render(
  <React.StrictMode>
    <App />
  </React.StrictMode>
);

export interface Tafila {
  text: string;
  pattern: string;
}

export interface ProsodyAnalysis {
  original: string;
  diacritized: string;
  prosodicWriting: string;
  symbols: string;
  meterName: string;
  tafilat: Tafila[];
  explanation?: string;
}

export interface AnalysisError {
  message: string;
}

import { GoogleGenAI, Type } from "@google/genai";
import { ProsodyAnalysis } from "../types";

const ai = new GoogleGenAI({ apiKey: process.env.API_KEY || "" });

export const analyzeVerse = async (verse: string): Promise<ProsodyAnalysis> => {
  const response = await ai.models.generateContent({
    model: "gemini-3-pro-preview",
    contents: `Analyze this Arabic poetic verse for prosody (Arud): "${verse}"
    Provide the following in your analysis:
    1. The verse with full diacritics.
    2. The prosodic writing (Kitaba Arudiya) where what's pronounced is written.
    3. The symbolic representation (/ for Harakah, 0 for Sukun).
    4. The name of the poetic meter (Bahr).
    5. The breakdown of the Taf'ilat (feet).
    6. A brief explanation of any poetic licenses or variations used.`,
    config: {
      responseMimeType: "application/json",
      responseSchema: {
        type: Type.OBJECT,
        properties: {
          original: { type: Type.STRING },
          diacritized: { type: Type.STRING },
          prosodicWriting: { type: Type.STRING },
          symbols: { type: Type.STRING },
          meterName: { type: Type.STRING },
          tafilat: {
            type: Type.ARRAY,
            items: {
              type: Type.OBJECT,
              properties: {
                text: { type: Type.STRING },
                pattern: { type: Type.STRING }
              },
              required: ["text", "pattern"]
            }
          },
          explanation: { type: Type.STRING }
        },
        required: ["original", "diacritized", "prosodicWriting", "symbols", "meterName", "tafilat"]
      }
    }
  });

  const text = response.text;
  if (!text) throw new Error("No response from AI");

  try {
    return JSON.parse(text) as ProsodyAnalysis;
  } catch (e) {
    console.error("Failed to parse AI response", text);
    throw new Error("عذراً، لم نتمكن من تحليل البيت الشعري. يرجى التأكد من كتابته بشكل صحيح.");
  }
};

import React from 'react';

interface VisualizerProps {
  symbols: string;
}

const Visualizer: React.FC<VisualizerProps> = ({ symbols }) => {
  const segments = symbols.split('');

  return (
    <div className="flex flex-wrap gap-1 justify-center items-center py-4 bg-emerald-50 rounded-lg border border-emerald-100" dir="ltr">
      {segments.map((s, i) => (
        <div 
          key={i} 
          className={`w-8 h-10 flex items-center justify-center text-2xl font-bold rounded shadow-sm
            ${s === '/' ? 'bg-amber-100 text-amber-800' : 'bg-blue-100 text-blue-800'}`}
        >
          {s}
        </div>
      ))}
    </div>
  );
};

export default Visualizer;

