        required: ["isCorrect", "score", "feedback", "correctedPattern"]
      }
    }
  });

  const text = response.text;
  if (!text) throw new Error("No response from AI");
  return JSON.parse(text) as EvaluationResult;
};

import React, { useState } from 'react';
