            {/* Taf'ilat Breakdown */}
            <section className="bg-white rounded-2xl p-8 shadow-sm border border-slate-100">
              <h3 className="text-lg font-bold text-slate-600 mb-6 flex items-center gap-2">
                <div className="w-2 h-2 rounded-full bg-purple-500"></div>
                التفاعيل (المقاطع الصوتية)
              </h3>
              <div className="flex flex-wrap gap-4 justify-center">
                {result.tafilat.map((taf, idx) => (
                  <div key={idx} className="flex flex-col items-center p-4 bg-slate-50 rounded-xl border border-slate-200 min-w-[120px]">
