import React, { useState, useEffect } from 'react';
import { analyzeVerse } from './services/geminiService';
import { ProsodyAnalysis, HistoryItem } from './types';
import Visualizer from './components/Visualizer';
import EvaluationPanel from './components/EvaluationPanel';
import HistoryPanel from './components/HistoryPanel';

const App: React.FC = () => {
  const [verse, setVerse] = useState('');
  const [loading, setLoading] = useState(false);
  const [result, setResult] = useState<ProsodyAnalysis | null>(null);
  const [error, setError] = useState<string | null>(null);
  const [showPractice, setShowPractice] = useState(false);
  const [history, setHistory] = useState<HistoryItem[]>([]);
  const [showHistory, setShowHistory] = useState(false);

  // Load history from localStorage on mount
  useEffect(() => {
    const saved = localStorage.getItem('mizan_history');
    if (saved) {
      try {
        setHistory(JSON.parse(saved));
      } catch (e) {
        console.error("Failed to load history", e);
      }
    }
  }, []);

  // Save history to localStorage whenever it changes
  useEffect(() => {
    localStorage.setItem('mizan_history', JSON.stringify(history));
  }, [history]);

  const addToHistory = (analysis: ProsodyAnalysis) => {
    const newItem: HistoryItem = {
      ...analysis,
      id: Math.random().toString(36).substr(2, 9),
      timestamp: Date.now()
    };

    // Check if verse already exists to avoid clutter (simple check)
    const exists = history.find(h => h.original === analysis.original);
    if (!exists) {
      setHistory(prev => [newItem, ...prev].slice(0, 20)); // Keep last 20
    }
  };

  const handleAnalyze = async () => {
    if (!verse.trim()) return;
    setLoading(true);
    setError(null);
    setResult(null);
    setShowPractice(false);
    try {
      const analysis = await analyzeVerse(verse);
      setResult(analysis);
      addToHistory(analysis);
    } catch (err: any) {
      setError(err.message || 'حدث خطأ غير متوقع');
    } finally {
      setLoading(false);
    }
  };

  const handleSelectHistory = (item: HistoryItem) => {
    setResult(item);
    setVerse(item.original);
    setShowPractice(false);
    setShowHistory(false);
    window.scrollTo({ top: 0, behavior: 'smooth' });
  };

  const handleDeleteHistory = (id: string) => {
    setHistory(prev => prev.filter(item => item.id !== id));
  };

  const handleClearHistory = () => {
    if (window.confirm('هل أنت متأكد من مسح جميع السجلات؟')) {
      setHistory([]);
    }
  };

  return (
    <div className="min-h-screen pb-20 text-slate-900 bg-[#fcfbf7]">
      {/* Header */}
      <header className="bg-emerald-900 text-white py-12 px-6 shadow-lg text-center relative overflow-hidden">
