            </div>

            {/* Symbolic Pattern */}
            <section className="bg-white rounded-2xl p-8 shadow-sm border border-slate-100">
              <h3 className="text-lg font-bold text-slate-600 mb-6 flex items-center gap-2">
                <div className="w-2 h-2 rounded-full bg-blue-500"></div>
                الرموز العروضية (/ حركي، 0 ساكن)
              </h3>
              <Visualizer symbols={result.symbols} />
            </section>

            {/* Taf'ilat Breakdown */}
            <section className="bg-white rounded-2xl p-8 shadow-sm border border-slate-100">
              <h3 className="text-lg font-bold text-slate-600 mb-6 flex items-center gap-2">
                <div className="w-2 h-2 rounded-full bg-purple-500"></div>
                التفاعيل (المقاطع الصوتية)
              </h3>
              <div className="flex flex-wrap gap-4 justify-center">
                {result.tafilat.map((taf, idx) => (
                  <div key={idx} className="flex flex-col items-center p-4 bg-slate-50 rounded-xl border border-slate-200 min-w-[120px]">
                    <span className="text-2xl font-amiri text-slate-800 mb-2">{taf.text}</span>
                    <span className="text-sm font-mono font-bold text-slate-400" dir="ltr">{taf.pattern}</span>
                  </div>
                ))}
              </div>
            </section>

            {/* Explanation */}
            {result.explanation && (
              <section className="bg-emerald-50 rounded-2xl p-8 border border-emerald-100 shadow-sm">
                <h3 className="text-lg font-bold text-emerald-800 mb-4">تحليل الميزان</h3>
                <p className="text-emerald-900 leading-relaxed text-lg">
                  {result.explanation}
                </p>
              </section>
            )}
          </div>
        )}
      </main>

      {/* Background Decor */}
      <div className="fixed bottom-0 right-0 p-8 opacity-5 pointer-events-none text-emerald-900">
        <svg width="200" height="200" viewBox="0 0 200 200">
          <path fill="currentColor" d="M100 0 C155.23 0 200 44.77 200 100 C200 155.23 155.23 200 100 200 C44.77 200 0 155.23 0 100 C0 44.77 44.77 0 100 0 M100 20 C144.18 20 180 55.82 180 100 C180 144.18 144.18 180 100 180 C55.82 180 20 144.18 20 100 C20 55.82 55.82 20 100 20" />
        </svg>
      </div>

      <footer className="mt-20 py-8 text-center text-slate-400 border-t border-slate-200">
        <p>© {new Date().getFullYear()} ميزان - ذكاء اصطناعي لخدمة الضاد</p>
      </footer>
    </div>
  );
};

export default App;

import React from 'react';

interface VisualizerProps {
  symbols: string;
}

const Visualizer: React.FC<VisualizerProps> = ({ symbols }) => {
  const segments = symbols.split('');

  const getLabel = (s: string) => {
    if (s === '/') return 'حركة (Harakah)';
    if (s === '0') return 'سكون (Sukun)';
    return '';
  };

  const getArabicLabel = (s: string) => {
    if (s === '/') return 'حركة';
    if (s === '0') return 'سكون';
    return '';
  };

  return (
    <div className="flex flex-wrap gap-2 justify-center items-center py-8 px-4 bg-emerald-50 rounded-2xl border border-emerald-100 shadow-inner" dir="ltr">
      {segments.map((s, i) => (
        <div 
          key={i} 
          className="group relative flex flex-col items-center"
        >
          {/* Tooltip */}
          <div className="absolute -top-12 opacity-0 group-hover:opacity-100 scale-90 group-hover:scale-100 transition-all duration-200 origin-bottom bg-slate-900 text-white text-xs px-3 py-1.5 rounded-lg whitespace-nowrap z-30 pointer-events-none shadow-xl border border-white/10 font-Tajawal">
            {getArabicLabel(s)}
            {/* Tooltip Arrow */}
            <div className="absolute top-full left-1/2 -translate-x-1/2 border-4 border-transparent border-t-slate-900"></div>
          </div>

          {/* Symbol Box */}
          <div 
            className={`w-10 h-12 flex items-center justify-center text-3xl font-bold rounded-xl shadow-sm transition-all duration-200 group-hover:-translate-y-1 group-hover:shadow-md
              ${s === '/' 
                ? 'bg-amber-100 text-amber-800 border-2 border-amber-200' 
                : 'bg-blue-100 text-blue-800 border-2 border-blue-200'}`}
            role="img"
            aria-label={getLabel(s)}
          >
            {s}
          </div>

          {/* Small label indicator underneath for always-on visual context if needed, 
              but since user requested tooltip on hover, the absolute div above handles it. */}
        </div>
      ))}
    </div>
  );
};

export default Visualizer;

