import React, { useState, useEffect } from 'react';
import { analyzeVerse } from './services/geminiService';
import { ProsodyAnalysis, HistoryItem } from './types';
import Visualizer from './components/Visualizer';
import AssessmentEngine from './components/AssessmentEngine';
import HistoryPanel from './components/HistoryPanel';

const App: React.FC = () => {
  const [verse, setVerse] = useState('');
  const [loading, setLoading] = useState(false);
  const [result, setResult] = useState<ProsodyAnalysis | null>(null);
  const [error, setError] = useState<string | null>(null);
  const [showAssessment, setShowAssessment] = useState(false);
  const [history, setHistory] = useState<HistoryItem[]>([]);
  const [showHistory, setShowHistory] = useState(false);

  // Load history from localStorage on mount
  useEffect(() => {
    const saved = localStorage.getItem('mizan_history');
    if (saved) {
      try {
        setHistory(JSON.parse(saved));
      } catch (e) {
        console.error("Failed to load history", e);
      }
    }
  }, []);

  // Save history to localStorage whenever it changes
  useEffect(() => {
    localStorage.setItem('mizan_history', JSON.stringify(history));
  }, [history]);

  const addToHistory = (analysis: ProsodyAnalysis) => {
    const newItem: HistoryItem = {
      ...analysis,
      id: Math.random().toString(36).substr(2, 9),
      timestamp: Date.now()
    };

    // Check if verse already exists to avoid clutter (simple check)
    const exists = history.find(h => h.original === analysis.original);
    if (!exists) {
      setHistory(prev => [newItem, ...prev].slice(0, 20)); // Keep last 20
    }
  };

  const handleAnalyze = async () => {
    if (!verse.trim()) return;
    setLoading(true);
    setError(null);
    setResult(null);
    setShowAssessment(false);
    try {
      const analysis = await analyzeVerse(verse);
      setResult(analysis);
      addToHistory(analysis);
    } catch (err: any) {
      setError(err.message || 'حدث خطأ غير متوقع');
    } finally {
      setLoading(false);
    }
  };

  const handleSelectHistory = (item: HistoryItem) => {
    setResult(item);
    setVerse(item.original);
    setShowAssessment(false);
    setShowHistory(false);
    window.scrollTo({ top: 0, behavior: 'smooth' });
  };

  const handleDeleteHistory = (id: string) => {
    setHistory(prev => prev.filter(item => item.id !== id));
  };

  const handleClearHistory = () => {
    if (window.confirm('هل أنت متأكد من مسح جميع السجلات؟')) {
      setHistory([]);
    }
  };

  return (
    <div className="min-h-screen pb-20 text-slate-900 bg-[#fcfbf7]">
      {/* Header */}
      <header className="bg-emerald-900 text-white py-12 px-6 shadow-lg text-center relative overflow-hidden">
        <div className="absolute inset-0 opacity-10 bg-[url('https://www.transparenttextures.com/patterns/arabic-pattern.png')] pointer-events-none"></div>
        <div className="relative z-10">
          <h1 className="text-5xl font-amiri font-bold mb-4 tracking-tight">ميزان</h1>
          <p className="text-emerald-100 text-lg max-w-2xl mx-auto leading-relaxed">
            المحرك الذكي للتقويم والقياس العروضي - حلل مهاراتك ومعارفك في علم العروض
          </p>
        </div>
      </header>

      <main className="max-w-4xl mx-auto px-4 -mt-10 relative z-10">
        {/* Input Card */}
        <div className="bg-white rounded-2xl shadow-xl p-8 border border-slate-100 mb-8 transition-all duration-500">
          <div className="flex items-center justify-between mb-4">
            <label htmlFor="verse" className="block text-xl font-bold text-slate-700">
              أدخل البيت الشعري أو الشطر
            </label>
            <button 
              onClick={() => setShowHistory(!showHistory)}
              className={`flex items-center gap-2 text-sm font-bold transition-all px-3 py-1 rounded-full
                ${showHistory ? 'bg-emerald-100 text-emerald-700' : 'text-slate-400 hover:text-emerald-600'}`}
            >
              <svg xmlns="http://www.w3.org/2000/svg" className="h-4 w-4" fill="none" viewBox="0 0 24 24" stroke="currentColor">
                <path strokeLinecap="round" strokeLinejoin="round" strokeWidth={2} d="M12 8v4l3 3m6-3a9 9 0 11-18 0 9 9 0 0118 0z" />
              </svg>
              السجل ({history.length})
            </button>
          </div>

          {showHistory ? (
            <div className="mb-6">
              <HistoryPanel 
                history={history} 
                onSelect={handleSelectHistory} 
                onDelete={handleDeleteHistory}
                onClear={handleClearHistory}
              />
              <button 
                onClick={() => setShowHistory(false)}
                className="w-full mt-6 py-2 text-slate-500 font-bold border-t border-slate-100 hover:text-emerald-600 transition-colors"
              >
                عودة للمحلل
              </button>
            </div>
          ) : (
            <>
              <textarea
                id="verse"
                className="w-full h-32 p-4 text-2xl font-amiri bg-slate-50 border border-slate-200 rounded-xl focus:ring-2 focus:ring-emerald-500 focus:border-transparent transition-all text-center resize-none"
                placeholder="مثال: قفا نبك من ذكرى حبيب ومنزلِ"
                value={verse}
                onChange={(e) => setVerse(e.target.value)}
                disabled={loading}
              />

              <button
                onClick={handleAnalyze}
                disabled={loading || !verse.trim()}
                className={`w-full mt-6 py-4 text-xl font-bold rounded-xl shadow-md transition-all flex items-center justify-center gap-3
                  ${loading ? 'bg-slate-300 text-slate-500 cursor-not-allowed' : 'bg-emerald-600 hover:bg-emerald-700 text-white shadow-emerald-200 shadow-lg hover:shadow-xl active:translate-y-1'}`}
              >
                {loading ? (
                  <>
                    <div className="w-5 h-5 border-4 border-white/30 border-t-white rounded-full animate-spin"></div>
                    جاري التقييم...
                  </>
                ) : (
                  'حلل البيت عروضياً'
                )}
              </button>
            </>
          )}
        </div>

        {/* Error State */}
        {error && !showHistory && (
          <div className="mt-8 p-6 bg-red-50 border border-red-100 rounded-2xl text-red-700 text-center animate-pulse">
            <p className="font-bold text-lg mb-2">عذراً، حدث خطأ</p>
            <p>{error}</p>
          </div>
        )}

        {/* Result Area */}
        {result && !showHistory && (
          <div className="mt-12 space-y-8 animate-in fade-in slide-in-from-bottom-5 duration-700">
            {/* Meter Hero */}
            <div className="bg-amber-50 rounded-2xl p-8 border border-amber-200 text-center shadow-sm flex flex-col items-center gap-2">
              <span className="text-amber-800 font-bold uppercase tracking-widest text-sm block">البحر الشعري</span>
              <h2 className="text-4xl font-amiri font-bold text-amber-900">{result.meterName}</h2>
              <button 
                onClick={() => setShowAssessment(!showAssessment)}
                className={`mt-4 px-8 py-3 rounded-full font-bold text-sm transition-all shadow-md flex items-center gap-2
                  ${showAssessment ? 'bg-slate-800 text-white' : 'bg-indigo-600 text-white hover:bg-indigo-700'}`}
              >
                <svg xmlns="http://www.w3.org/2000/svg" className="h-5 w-5" viewBox="0 0 20 20" fill="currentColor">
                  <path fillRule="evenodd" d="M18 10a8 8 0 11-16 0 8 8 0 0116 0zm-7-4a1 1 0 11-2 0 1 1 0 012 0zM9 9a1 1 0 000 2v3a1 1 0 001 1h1a1 1 0 100-2v-3a1 1 0 00-1-1H9z" clipRule="evenodd" />
                </svg>
                {showAssessment ? 'إغفاء محرك التقييم' : 'ابدأ اختبار المعارف والمهارات'}
              </button>
            </div>

            {/* Assessment Dashboard */}
            {showAssessment && <AssessmentEngine analysis={result} />}

            <div className="grid grid-cols-1 md:grid-cols-2 gap-8">
              {/* Diacritized Verse */}
              <section className="bg-white rounded-2xl p-6 shadow-sm border border-slate-100">
                <h3 className="text-lg font-bold text-slate-600 mb-4 flex items-center gap-2">
                  <div className="w-2 h-2 rounded-full bg-emerald-500"></div>
                  النص مشكولاً
                </h3>
                <p className="text-3xl font-amiri leading-loose text-slate-800 text-center bg-slate-50 p-6 rounded-xl">
                  {result.diacritized}
                </p>
              </section>

              {/* Prosodic Writing */}
              <section className="bg-white rounded-2xl p-6 shadow-sm border border-slate-100">
                <h3 className="text-lg font-bold text-slate-600 mb-4 flex items-center gap-2">
                  <div className="w-2 h-2 rounded-full bg-amber-500"></div>
                  الكتابة العروضية
                </h3>
                <p className="text-3xl font-amiri leading-loose text-slate-800 text-center bg-amber-50/30 p-6 rounded-xl border border-dashed border-amber-200">
                  {result.prosodicWriting}
                </p>
              </section>
            </div>

            {/* Symbolic Pattern */}
            <section className="bg-white rounded-2xl p-8 shadow-sm border border-slate-100">
              <h3 className="text-lg font-bold text-slate-600 mb-6 flex items-center gap-2">
                <div className="w-2 h-2 rounded-full bg-blue-500"></div>
                الرموز العروضية (/ حركي، 0 ساكن)
              </h3>
              <Visualizer symbols={result.symbols} />
            </section>

            {/* Taf'ilat Breakdown */}
            <section className="bg-white rounded-2xl p-8 shadow-sm border border-slate-100">
              <h3 className="text-lg font-bold text-slate-600 mb-6 flex items-center gap-2">
                <div className="w-2 h-2 rounded-full bg-purple-500"></div>
                التفاعيل (المقاطع الصوتية)
              </h3>
              <div className="flex flex-wrap gap-4 justify-center">
                {result.tafilat.map((taf, idx) => (
                  <div key={idx} className="group relative flex flex-col items-center p-4 bg-slate-50 rounded-xl border border-slate-200 min-w-[120px] transition-all hover:bg-slate-100 hover:border-slate-300">
                    {/* Tooltip */}
                    <div className="absolute -top-12 opacity-0 group-hover:opacity-100 scale-90 group-hover:scale-100 transition-all duration-200 origin-bottom bg-slate-900 text-white text-xs px-3 py-1.5 rounded-lg whitespace-nowrap z-30 pointer-events-none shadow-xl border border-white/10 font-Tajawal text-center">
                      <p className="font-bold mb-0.5">{taf.text}</p>
                      <p className="font-mono opacity-80" dir="ltr">{taf.pattern}</p>
                      <div className="absolute top-full left-1/2 -translate-x-1/2 border-4 border-transparent border-t-slate-900"></div>
                    </div>

                    <span className="text-2xl font-amiri text-slate-800 mb-2">{taf.text}</span>
                    <span className="text-sm font-mono font-bold text-slate-400" dir="ltr">{taf.pattern}</span>
                  </div>
                ))}
              </div>
            </section>

            {/* Explanation */}
            {result.explanation && (
              <section className="bg-emerald-50 rounded-2xl p-8 border border-emerald-100 shadow-sm">
                <h3 className="text-lg font-bold text-emerald-800 mb-4 flex items-center gap-2">
                  <svg xmlns="http://www.w3.org/2000/svg" className="h-5 w-5" viewBox="0 0 20 20" fill="currentColor">
                    <path fillRule="evenodd" d="M18 10a8 8 0 11-16 0 8 8 0 0116 0zm-8-3a1 1 0 00-.832.445l-2 3a1 1 0 101.664 1.11L10 9.555l1.168 1.751a1 1 0 101.664-1.11l-2-3A1 1 0 0010 7z" clipRule="evenodd" />
                  </svg>
                  تحليل الميزان البيداغوجي
                </h3>
                <p className="text-emerald-900 leading-relaxed text-lg">
                  {result.explanation}
                </p>
              </section>
            )}
          </div>
        )}
      </main>

      {/* Background Decor */}
      <div className="fixed bottom-0 right-0 p-8 opacity-5 pointer-events-none text-emerald-900">
        <svg width="200" height="200" viewBox="0 0 200 200">
          <path fill="currentColor" d="M100 0 C155.23 0 200 44.77 200 100 C200 155.23 155.23 200 100 200 C44.77 200 0 155.23 0 100 C0 44.77 44.77 0 100 0 M100 20 C144.18 20 180 55.82 180 100 C180 144.18 144.18 180 100 180 C55.82 180 20 144.18 20 100 C20 55.82 55.82 20 100 20" />
        </svg>
      </div>

      <footer className="mt-20 py-8 text-center text-slate-400 border-t border-slate-200">
        <p>© {new Date().getFullYear()} ميزان - ذكاء اصطناعي لخدمة الضاد والتقويم التربوي</p>
      </footer>
    </div>
  );
};

