import React, { useState, useEffect } from 'react';
import { analyzeVerse } from './services/geminiService';
import { ProsodyAnalysis, HistoryItem, StudentStats } from './types';
import Visualizer from './components/Visualizer';
import AssessmentEngine from './components/AssessmentEngine';
import HistoryPanel from './components/HistoryPanel';
import LearningDashboard from './components/LearningDashboard';
import KnowledgeBase from './components/KnowledgeBase';

type ViewState = 'analyzer' | 'dashboard' | 'knowledge';

const App: React.FC = () => {
  const [activeView, setActiveView] = useState<ViewState>('analyzer');
  const [verse, setVerse] = useState('');
  const [loading, setLoading] = useState(false);
  const [result, setResult] = useState<ProsodyAnalysis | null>(null);
  const [error, setError] = useState<string | null>(null);
  const [showAssessment, setShowAssessment] = useState(false);
  const [history, setHistory] = useState<HistoryItem[]>([]);
  const [showHistory, setShowHistory] = useState(false);

  const [stats, setStats] = useState<StudentStats>({
    interactionsCount: 0,
    strengths: [],
    recurringErrors: [],
    completedQuizzes: 0,
    averageScore: 0
  });

  // Load persistence data
  useEffect(() => {
    const savedHistory = localStorage.getItem('mizan_history');
    if (savedHistory) setHistory(JSON.parse(savedHistory));

    const savedStats = localStorage.getItem('mizan_stats');
    if (savedStats) setStats(JSON.parse(savedStats));
  }, []);

  // Save persistence data
  useEffect(() => {
    localStorage.setItem('mizan_history', JSON.stringify(history));
    localStorage.setItem('mizan_stats', JSON.stringify(stats));
  }, [history, stats]);

  const handleAnalyze = async () => {
    if (!verse.trim()) return;
    setLoading(true);
    setError(null);
    setResult(null);
    setShowAssessment(false);
    try {
      const analysis = await analyzeVerse(verse);
      setResult(analysis);

      // Update history
      const newItem: HistoryItem = {
        ...analysis,
        id: Math.random().toString(36).substr(2, 9),
        timestamp: Date.now()
      };
      if (!history.find(h => h.original === analysis.original)) {
        setHistory(prev => [newItem, ...prev].slice(0, 20));
      }

      // Update stats
      setStats(prev => ({
        ...prev,
        interactionsCount: prev.interactionsCount + 1
      }));

    } catch (err: any) {
      setError(err.message || 'حدث خطأ غير متوقع');
    } finally {
      setLoading(false);
    }
  };

  const handleSelectHistory = (item: HistoryItem) => {
    setResult(item);
    setVerse(item.original);
    setShowAssessment(false);
    setShowHistory(false);
    setActiveView('analyzer');
    window.scrollTo({ top: 0, behavior: 'smooth' });
  };

  return (
    <div className="min-h-screen pb-20 text-slate-900 bg-[#fcfbf7]">
      {/* Header */}
      <header className="bg-emerald-900 text-white py-12 px-6 shadow-lg text-center relative overflow-hidden">
        <div className="absolute inset-0 opacity-10 bg-[url('https://www.transparenttextures.com/patterns/arabic-pattern.png')] pointer-events-none"></div>
        <div className="relative z-10">
          <h1 className="text-5xl font-amiri font-bold mb-4 tracking-tight">ميزان</h1>
          <p className="text-emerald-100 text-lg max-w-2xl mx-auto leading-relaxed">
            منصة التحليل الإيقاعي والتقويم التربوي الذكي للشعر العربي
          </p>
        </div>
      </header>

      {/* Navigation */}
      <nav className="max-w-4xl mx-auto px-4 mt-8 flex justify-center">
        <div className="flex bg-white p-1 rounded-2xl shadow-sm border border-slate-100 w-full md:w-auto">
          <button 
            onClick={() => setActiveView('analyzer')}
            className={`px-6 py-2 rounded-xl font-bold transition-all ${activeView === 'analyzer' ? 'bg-emerald-600 text-white shadow-md' : 'text-slate-500 hover:bg-slate-50'}`}
          >
            المحلل الإيقاعي
          </button>
          <button 
            onClick={() => setActiveView('dashboard')}
            className={`px-6 py-2 rounded-xl font-bold transition-all ${activeView === 'dashboard' ? 'bg-emerald-600 text-white shadow-md' : 'text-slate-500 hover:bg-slate-50'}`}
          >
            لوحة المهارات
          </button>
          <button 
            onClick={() => setActiveView('knowledge')}
            className={`px-6 py-2 rounded-xl font-bold transition-all ${activeView === 'knowledge' ? 'bg-emerald-600 text-white shadow-md' : 'text-slate-500 hover:bg-slate-50'}`}
          >
            قاعدة البحور
          </button>
        </div>
      </nav>

      <main className="max-w-4xl mx-auto px-4 mt-10 relative z-10">

        {activeView === 'analyzer' && (
          <>
            {/* Input Card */}
            <div className="bg-white rounded-2xl shadow-xl p-8 border border-slate-100 mb-8 transition-all">
              <div className="flex items-center justify-between mb-4">
                <label htmlFor="verse" className="block text-xl font-bold text-slate-700">
                  أدخل النص الشعري للتحليل
                </label>
                <button 
                  onClick={() => setShowHistory(!showHistory)}
                  className={`flex items-center gap-2 text-sm font-bold transition-all px-3 py-1 rounded-full
                    ${showHistory ? 'bg-emerald-100 text-emerald-700' : 'text-slate-400 hover:text-emerald-600'}`}
                >
                  السجل ({history.length})
                </button>
              </div>

              {showHistory ? (
                <HistoryPanel 
                  history={history} 
                  onSelect={handleSelectHistory} 
                  onDelete={(id) => setHistory(h => h.filter(i => i.id !== id))}
                  onClear={() => setHistory([])}
                />
              ) : (
                <>
                  <textarea
                    id="verse"
                    className="w-full h-32 p-4 text-2xl font-amiri bg-slate-50 border border-slate-200 rounded-xl focus:ring-2 focus:ring-emerald-500 transition-all text-center resize-none"
                    placeholder="مثال: يا ليلُ الصبُّ متى غَدُهُ .. أقِيامُ السَّاعَةِ مَوْعِدُهُ"
                    value={verse}
                    onChange={(e) => setVerse(e.target.value)}
                    disabled={loading}
                  />
                  <button
                    onClick={handleAnalyze}
                    disabled={loading || !verse.trim()}
                    className={`w-full mt-6 py-4 text-xl font-bold rounded-xl shadow-lg transition-all flex items-center justify-center gap-3
                      ${loading ? 'bg-slate-300 text-slate-500 cursor-not-allowed' : 'bg-emerald-600 hover:bg-emerald-700 text-white active:translate-y-1'}`}
                  >
                    {loading ? 'جاري التحليل...' : 'حلل البيت عروضياً'}
