                </>
              )}
            </div>

            {error && <div className="p-6 bg-red-50 border border-red-100 rounded-2xl text-red-700 text-center mb-8">{error}</div>}

            {result && (
              <div className="space-y-8 animate-in fade-in duration-700">
                {/* Meter Hero */}
                <div className="bg-amber-50 rounded-2xl p-8 border border-amber-200 text-center shadow-sm">
                  <span className="text-amber-800 font-bold uppercase tracking-widest text-sm">البحر الشعري</span>
                  <h2 className="text-4xl font-amiri font-bold text-amber-900 mt-2">{result.meterName}</h2>
                  <button 
                    onClick={() => setShowAssessment(!showAssessment)}
                    className="mt-6 px-8 py-3 bg-indigo-600 text-white rounded-full font-bold shadow-md hover:bg-indigo-700 transition-all flex items-center gap-2 mx-auto"
                  >
                    {showAssessment ? 'إخفاء التقييم' : 'بدء تقويم المهارات والمعارف'}
                  </button>
                </div>

                {showAssessment && <AssessmentEngine analysis={result} />}

                <div className="grid grid-cols-1 md:grid-cols-2 gap-8">
                  <section className="bg-white rounded-2xl p-6 shadow-sm border border-slate-100">
                    <h3 className="text-lg font-bold text-slate-600 mb-4">النص مشكولاً</h3>
                    <p className="text-3xl font-amiri leading-loose text-slate-800 text-center bg-slate-50 p-6 rounded-xl">{result.diacritized}</p>
                  </section>
                  <section className="bg-white rounded-2xl p-6 shadow-sm border border-slate-100">
                    <h3 className="text-lg font-bold text-slate-600 mb-4">الكتابة العروضية</h3>
                    <p className="text-3xl font-amiri leading-loose text-slate-800 text-center bg-amber-50/30 p-6 rounded-xl border border-dashed border-amber-200">{result.prosodicWriting}</p>
                  </section>
                </div>

                <section className="bg-white rounded-2xl p-8 shadow-sm border border-slate-100">
                  <h3 className="text-lg font-bold text-slate-600 mb-6">الرموز العروضية (/ حركي، 0 ساكن)</h3>
                  <Visualizer symbols={result.symbols} />
                </section>

                <section className="bg-white rounded-2xl p-8 shadow-sm border border-slate-100">
                  <h3 className="text-lg font-bold text-slate-600 mb-6">التفاعيل والمقاطع</h3>
