                          <p className="font-mono opacity-80" dir="ltr">{taf.pattern}</p>
                        </div>
                        <span className="text-2xl font-amiri text-slate-800 mb-2">{taf.text}</span>
                        <span className="text-sm font-mono font-bold text-slate-400" dir="ltr">{taf.pattern}</span>
                      </div>
                    ))}
                  </div>
                </section>

                {result.explanation && (
                  <section className="bg-emerald-50 rounded-2xl p-8 border border-emerald-100 text-emerald-900">
                    <h3 className="font-bold mb-4 flex items-center gap-2">
                      <svg xmlns="http://www.w3.org/2000/svg" className="h-5 w-5" viewBox="0 0 20 20" fill="currentColor">
                        <path fillRule="evenodd" d="M18 10a8 8 0 11-16 0 8 8 0 0116 0zm-7-4a1 1 0 11-2 0 1 1 0 012 0zM9 9a1 1 0 000 2v3a1 1 0 001 1h1a1 1 0 100-2v-3a1 1 0 00-1-1H9z" clipRule="evenodd" />
                      </svg>
                      التحليل البيداغوجي للميزان
                    </h3>
                    <p className="leading-relaxed text-lg">{result.explanation}</p>
                  </section>
                )}
              </div>
            )}
          </>
        )}

        {activeView === 'dashboard' && <LearningDashboard stats={stats} />}
        {activeView === 'knowledge' && <KnowledgeBase />}

      </main>

      <footer className="mt-20 py-8 text-center text-slate-400 border-t border-slate-200">
        <p>© {new Date().getFullYear()} ميزان | التميز في علوم الضاد الرقمية</p>
      </footer>
    </div>
  );
};

