import React, { useState, useEffect } from 'react';
import { analyzeVerse } from './services/geminiService';
import { ProsodyAnalysis, HistoryItem, StudentStats } from './types';
import Visualizer from './components/Visualizer';
import AssessmentEngine from './components/AssessmentEngine';
import HistoryPanel from './components/HistoryPanel';
import LearningDashboard from './components/LearningDashboard';
import KnowledgeBase from './components/KnowledgeBase';

type ViewState = 'analyzer' | 'dashboard' | 'knowledge';

const App: React.FC = () => {
  const [activeView, setActiveView] = useState<ViewState>('analyzer');
  const [verse, setVerse] = useState('');
  const [loading, setLoading] = useState(false);
  const [result, setResult] = useState<ProsodyAnalysis | null>(null);
  const [error, setError] = useState<string | null>(null);
  const [showAssessment, setShowAssessment] = useState(false);
  const [history, setHistory] = useState<HistoryItem[]>([]);
  const [showHistory, setShowHistory] = useState(false);
  const [saveStatus, setSaveStatus] = useState<boolean>(false);

  const [stats, setStats] = useState<StudentStats>({
    interactionsCount: 0,
    strengths: [],
    recurringErrors: [],
    completedQuizzes: 0,
    averageScore: 0
  });

  useEffect(() => {
    const savedHistory = localStorage.getItem('mizan_history');
    if (savedHistory) setHistory(JSON.parse(savedHistory));
    const savedStats = localStorage.getItem('mizan_stats');
    if (savedStats) setStats(JSON.parse(savedStats));
  }, []);

  useEffect(() => {
    localStorage.setItem('mizan_history', JSON.stringify(history));
    localStorage.setItem('mizan_stats', JSON.stringify(stats));
  }, [history, stats]);

  const handleAnalyze = async () => {
    if (!verse.trim()) return;
    setLoading(true);
    setError(null);
    setResult(null);
    setShowAssessment(false);
    setSaveStatus(false);
    try {
      const analysis = await analyzeVerse(verse);
      setResult(analysis);

      const newItem: HistoryItem = {
        ...analysis,
        id: Math.random().toString(36).substr(2, 9),
        timestamp: Date.now()
      };
      if (!history.find(h => h.original === analysis.original)) {
        setHistory(prev => [newItem, ...prev].slice(0, 20));
      }

      setStats(prev => ({
        ...prev,
        interactionsCount: prev.interactionsCount + 1
      }));

    } catch (err: any) {
      setError(err.message || 'حدث خطأ في محرك الميزان');
    } finally {
      setLoading(false);
    }
  };

  const handleSaveToLocalStorage = () => {
    if (!result) return;

    const savedVersesKey = 'mizan_saved_verses';
    const existingSaved = localStorage.getItem(savedVersesKey);
    const savedList: HistoryItem[] = existingSaved ? JSON.parse(existingSaved) : [];

    const newItem: HistoryItem = {
      ...result,
      id: Math.random().toString(36).substr(2, 9),
      timestamp: Date.now()
    };

    savedList.push(newItem);
    localStorage.setItem(savedVersesKey, JSON.stringify(savedList));

    setSaveStatus(true);
    setTimeout(() => setSaveStatus(false), 3000);
  };

  const handleSelectHistory = (item: HistoryItem) => {
    setResult(item);
    setVerse(item.original);
    setShowAssessment(false);
    setShowHistory(false);
    setSaveStatus(false);
    setActiveView('analyzer');
    window.scrollTo({ top: 0, behavior: 'smooth' });
  };

  return (
    <div className="min-h-screen pb-20 text-slate-900 bg-[#fcfbf7] font-Tajawal">
      {/* Decorative Top Border */}
      <div className="h-2 bg-gradient-to-l from-emerald-800 via-emerald-600 to-emerald-800 w-full"></div>

      {/* Modern Header */}
      <header className="bg-white py-8 px-6 shadow-sm relative overflow-hidden border-b border-slate-100">
        <div className="max-w-5xl mx-auto flex flex-col md:flex-row items-center justify-between gap-6 relative z-10">
          <div className="flex items-center gap-4">
            <div className="w-16 h-16 bg-emerald-900 rounded-2xl flex items-center justify-center shadow-lg transform -rotate-3">
              <span className="text-3xl font-amiri text-white font-bold">م</span>
            </div>
            <div>
              <h1 className="text-4xl font-amiri font-bold text-emerald-900 tracking-tight">ميزان الذكي</h1>
              <p className="text-slate-500 font-medium">نظام التقطيع الإيقاعي والتقويم التربوي</p>
            </div>
          </div>

          <div className="flex bg-slate-100 p-1.5 rounded-2xl border border-slate-200 shadow-inner">
            <button 
              onClick={() => setActiveView('analyzer')}
              className={`px-6 py-2.5 rounded-xl font-bold transition-all flex items-center gap-2 ${activeView === 'analyzer' ? 'bg-white text-emerald-700 shadow-md' : 'text-slate-500 hover:text-emerald-800'}`}
            >
              <svg xmlns="http://www.w3.org/2000/svg" className="h-5 w-5" viewBox="0 0 20 20" fill="currentColor">
                <path fillRule="evenodd" d="M7 2a1 1 0 00-1 1v1H4a2 2 0 00-2 2v10a2 2 0 002 2h12a2 2 0 002-2V6a2 2 0 00-2-2h-2V3a1 1 0 00-1-1H7zM6 5v1h8V5H6z" clipRule="evenodd" />
              </svg>
              المختبر العروضي
            </button>
            <button 
              onClick={() => setActiveView('dashboard')}
              className={`px-6 py-2.5 rounded-xl font-bold transition-all flex items-center gap-2 ${activeView === 'dashboard' ? 'bg-white text-emerald-700 shadow-md' : 'text-slate-500 hover:text-emerald-800'}`}
            >
              <svg xmlns="http://www.w3.org/2000/svg" className="h-5 w-5" viewBox="0 0 20 20" fill="currentColor">
                <path d="M2 11a1 1 0 011-1h2a1 1 0 011 1v5a1 1 0 01-1 1H3a1 1 0 01-1-1v-5zM8 7a1 1 0 011-1h2a1 1 0 011 1v9a1 1 0 01-1 1H9a1 1 0 01-1-1V7zM14 4a1 1 0 011-1h2a1 1 0 011 1v12a1 1 0 01-1 1h-2a1 1 0 01-1-1V4z" />
              </svg>
              لوحة المهارات
            </button>
            <button 
              onClick={() => setActiveView('knowledge')}
              className={`px-6 py-2.5 rounded-xl font-bold transition-all flex items-center gap-2 ${activeView === 'knowledge' ? 'bg-white text-emerald-700 shadow-md' : 'text-slate-500 hover:text-emerald-800'}`}
            >
              <svg xmlns="http://www.w3.org/2000/svg" className="h-5 w-5" viewBox="0 0 20 20" fill="currentColor">
                <path d="M9 4.804A7.993 7.993 0 002 12a7.993 7.993 0 007 7.196V4.804zM11 4.804v14.392A7.993 7.993 0 0018 12a7.993 7.993 0 00-7-7.196z" />
              </svg>
              موسوعة البحور
            </button>
          </div>
        </div>
      </header>

      <main className="max-w-5xl mx-auto px-4 mt-12 relative z-10">

        {activeView === 'analyzer' && (
          <div className="grid grid-cols-1 lg:grid-cols-12 gap-8">

            {/* Right Column: Input & Results */}
            <div className="lg:col-span-8 space-y-8">
              <div className="bg-white rounded-3xl shadow-xl shadow-emerald-900/5 p-8 border border-slate-100 relative overflow-hidden">
                <div className="absolute top-0 right-0 w-32 h-32 bg-emerald-50 rounded-full -mr-16 -mt-16 opacity-50"></div>

                <h3 className="text-2xl font-bold text-slate-800 mb-6 flex items-center gap-3">
                  <span className="w-8 h-8 bg-emerald-100 text-emerald-700 rounded-lg flex items-center justify-center text-sm">1</span>
                  المحلل الإيقاعي الذكي
                </h3>

                {showHistory ? (
                  <div className="animate-in fade-in zoom-in-95">
                    <HistoryPanel 
                      history={history} 
                      onSelect={handleSelectHistory} 
                      onDelete={(id) => setHistory(h => h.filter(i => i.id !== id))}
                      onClear={() => setHistory([])}
                    />
                    <button 
                      onClick={() => setShowHistory(false)}
                      className="w-full mt-6 py-3 text-emerald-700 font-bold bg-emerald-50 rounded-xl hover:bg-emerald-100 transition-colors"
                    >
                      العودة للمختبر
                    </button>
                  </div>
                ) : (
                  <>
                    <div className="relative group">
                      <textarea
                        id="verse"
                        className="w-full h-40 p-6 text-3xl font-amiri leading-relaxed bg-slate-50 border-2 border-slate-100 rounded-2xl focus:ring-4 focus:ring-emerald-500/10 focus:border-emerald-500 transition-all text-center resize-none shadow-inner"
                        placeholder="اكتب البيت الشعري هنا للحصول على الوزن والتقطيع..."
                        value={verse}
                        onChange={(e) => setVerse(e.target.value)}
                        disabled={loading}
                      />
                      <div className="absolute bottom-4 right-4 text-xs text-slate-400 font-bold uppercase tracking-widest opacity-0 group-hover:opacity-100 transition-opacity">
                        AI Enabled Analysis
                      </div>
                    </div>

                    <div className="flex gap-4 mt-6">
                      <button
                        onClick={handleAnalyze}
                        disabled={loading || !verse.trim()}
                        className={`flex-1 py-4 text-xl font-bold rounded-2xl shadow-lg transition-all flex items-center justify-center gap-3
                          ${loading ? 'bg-slate-200 text-slate-400 cursor-not-allowed' : 'bg-emerald-600 hover:bg-emerald-700 text-white hover:-translate-y-1 active:translate-y-0 shadow-emerald-200'}`}
                      >
                        {loading ? (
                          <div className="flex items-center gap-3">
                            <div className="w-6 h-6 border-4 border-slate-300 border-t-emerald-600 rounded-full animate-spin"></div>
                            <span>جاري معالجة الإيقاع...</span>
                          </div>
                        ) : 'بدء التحليل الرقمي'}
                      </button>

                      <button 
                        onClick={() => setShowHistory(true)}
                        className="w-14 h-14 bg-slate-100 text-slate-500 rounded-2xl flex items-center justify-center hover:bg-slate-200 transition-all border border-slate-200"
                        title="سجل التحليلات"
                      >
                        <svg xmlns="http://www.w3.org/2000/svg" className="h-6 w-6" fill="none" viewBox="0 0 24 24" stroke="currentColor">
                          <path strokeLinecap="round" strokeLinejoin="round" strokeWidth={2} d="M12 8v4l3 3m6-3a9 9 0 11-18 0 9 9 0 0118 0z" />
                        </svg>
                      </button>
                    </div>
                  </>
                )}
              </div>

              {error && <div className="p-6 bg-red-50 border-2 border-red-100 rounded-3xl text-red-700 text-center font-bold animate-bounce">{error}</div>}

              {result && (
                <div className="space-y-8 animate-in fade-in slide-in-from-bottom-8 duration-700">
                  {/* Bahr & Assessment Toggle */}
                  <div className="bg-amber-50 rounded-3xl p-8 border border-amber-200 text-center shadow-md relative overflow-hidden group">
                    <div className="absolute top-0 left-0 w-2 h-full bg-amber-400"></div>
                    <span className="text-amber-800 font-bold uppercase tracking-[0.2em] text-xs block mb-2 opacity-60">Result Identified</span>
                    <h2 className="text-5xl font-amiri font-bold text-amber-900 drop-shadow-sm">{result.meterName}</h2>
                    <div className="mt-6 flex flex-wrap justify-center gap-4">
                      <button 
                        onClick={() => setShowAssessment(!showAssessment)}
                        className={`px-8 py-3.5 rounded-2xl font-bold shadow-xl transition-all flex items-center gap-3 transform hover:scale-105
                          ${showAssessment ? 'bg-slate-800 text-white ring-4 ring-slate-100' : 'bg-indigo-600 text-white hover:bg-indigo-700 shadow-indigo-200'}`}
                      >
                        <svg xmlns="http://www.w3.org/2000/svg" className="h-5 w-5" viewBox="0 0 20 20" fill="currentColor">
                          <path d="M10.394 2.827a1 1 0 00-.788 0l-7 3a1 1 0 000 1.848l7 3a1 1 0 00.788 0l7-3a1 1 0 000-1.848l-7-3zM3.94 6L10 8.599 16.06 6 10 3.401 3.94 6z" />
                          <path d="M4.588 9L10 11.318 15.412 9A1 1 0 0117 10.312V14.12a1 1 0 01-.606.919l-5.636 2.416a1 1 0 01-.788 0L4.336 15.04a1 1 0 01-.606-.92V10.312A1 1 0 014.588 9z" />
                        </svg>
                        {showAssessment ? 'إغلاق نافذة الاختبار' : 'بدء تقويم المهارات والمعارف'}
                      </button>

                      <button 
                        onClick={handleSaveToLocalStorage}
                        className={`px-8 py-3.5 rounded-2xl font-bold shadow-xl transition-all flex items-center gap-3 transform hover:scale-105
                          ${saveStatus ? 'bg-emerald-100 text-emerald-800 ring-2 ring-emerald-300' : 'bg-white text-slate-700 hover:bg-slate-50 border border-slate-200'}`}
                      >
                        {saveStatus ? (
                          <>
                            <svg xmlns="http://www.w3.org/2000/svg" className="h-5 w-5 text-emerald-600" viewBox="0 0 20 20" fill="currentColor">
                              <path fillRule="evenodd" d="M16.707 5.293a1 1 0 010 1.414l-8 8a1 1 0 01-1.414 0l-4-4a1 1 0 011.414-1.414L8 12.586l7.293-7.293a1 1 0 011.414 0z" clipRule="evenodd" />
                            </svg>
                            تم الحفظ!
                          </>
                        ) : (
                          <>
                            <svg xmlns="http://www.w3.org/2000/svg" className="h-5 w-5" viewBox="0 0 20 20" fill="currentColor">
                              <path d="M5 4a2 2 0 012-2h6a2 2 0 012 2v14l-5-2.5L5 18V4z" />
                            </svg>
                            حفظ التحليل
                          </>
                        )}
                      </button>
                    </div>
                  </div>

                  {showAssessment && <AssessmentEngine analysis={result} />}

                  <div className="grid grid-cols-1 md:grid-cols-2 gap-8">
                    <div className="bg-white rounded-3xl p-8 shadow-sm border border-slate-100 hover:shadow-md transition-shadow">
                      <h4 className="text-sm font-bold text-slate-400 mb-6 uppercase tracking-widest border-b pb-2">النص المشكول</h4>
                      <p className="text-3xl font-amiri leading-relaxed text-slate-800 text-center">{result.diacritized}</p>
                    </div>
                    <div className="bg-white rounded-3xl p-8 shadow-sm border border-slate-100 hover:shadow-md transition-shadow">
                      <h4 className="text-sm font-bold text-slate-400 mb-6 uppercase tracking-widest border-b pb-2">الكتابة العروضية</h4>
                      <p className="text-3xl font-amiri leading-relaxed text-emerald-800 text-center">{result.prosodicWriting}</p>
                    </div>
                  </div>

                  <div className="bg-white rounded-3xl p-8 shadow-sm border border-slate-100">
                    <h4 className="text-sm font-bold text-slate-400 mb-8 uppercase tracking-widest border-b pb-2 text-center">التوقيع الإيقاعي الرقمي</h4>
                    <Visualizer symbols={result.symbols} />
                  </div>

                  <div className="bg-white rounded-3xl p-8 shadow-sm border border-slate-100">
                    <h4 className="text-sm font-bold text-slate-400 mb-10 uppercase tracking-widest border-b pb-2 text-center">مصفوفة التفاعيل</h4>
                    <div className="flex flex-wrap gap-6 justify-center">
                      {result.tafilat.map((taf, idx) => (
                        <div key={idx} className="group relative flex flex-col items-center p-6 bg-slate-50 rounded-2xl border-2 border-slate-100 transition-all hover:bg-emerald-50 hover:border-emerald-200 hover:-translate-y-2">
                          <div className="absolute -top-14 opacity-0 group-hover:opacity-100 transition-all bg-slate-900 text-white text-xs px-4 py-2 rounded-xl whitespace-nowrap z-30 pointer-events-none shadow-xl border border-white/10 text-center">
                            <p className="font-bold mb-1">{taf.text}</p>
                            <p className="font-mono opacity-60" dir="ltr">{taf.pattern}</p>
                            <div className="absolute top-full left-1/2 -translate-x-1/2 border-6 border-transparent border-t-slate-900"></div>
                          </div>
                          <span className="text-3xl font-amiri text-slate-800 mb-3">{taf.text}</span>
                          <span className="text-sm font-mono font-bold text-slate-400 bg-white px-3 py-1 rounded-full border border-slate-200 shadow-sm" dir="ltr">{taf.pattern}</span>
                        </div>
                      ))}
                    </div>
                  </div>

                  {result.explanation && (
                    <div className="bg-emerald-900 rounded-3xl p-10 text-white shadow-2xl relative overflow-hidden">
                      <div className="absolute bottom-0 right-0 w-64 h-64 bg-emerald-800 rounded-full -mb-32 -mr-32 opacity-20"></div>
                      <h3 className="text-xl font-bold mb-6 flex items-center gap-3">
                        <svg xmlns="http://www.w3.org/2000/svg" className="h-6 w-6 text-emerald-400" viewBox="0 0 20 20" fill="currentColor">
                          <path fillRule="evenodd" d="M18 10a8 8 0 11-16 0 8 8 0 0116 0zm-7-4a1 1 0 11-2 0 1 1 0 012 0zM9 9a1 1 0 000 2v3a1 1 0 001 1h1a1 1 0 100-2v-3a1 1 0 00-1-1H9z" clipRule="evenodd" />
                        </svg>
                        التعليق البيداغوجي
                      </h3>
                      <p className="leading-loose text-emerald-50 text-xl font-medium font-Tajawal italic">"{result.explanation}"</p>
                    </div>
                  )}
                </div>
              )}
            </div>

            {/* Left Column: Quick Stats / Tips */}
            <div className="lg:col-span-4 space-y-8">
              <div className="bg-white rounded-3xl p-8 shadow-sm border border-slate-100">
                <h4 className="font-bold text-slate-800 mb-6 flex items-center gap-2">
                  <span className="w-2 h-6 bg-emerald-600 rounded-full"></span>
                  نظرة سريعة
                </h4>
                <div className="space-y-6">
                  <div className="flex items-center justify-between">
                    <span className="text-slate-500">التحليلات اليوم</span>
                    <span className="font-bold text-emerald-700">{stats.interactionsCount}</span>
                  </div>
                  <div className="flex items-center justify-between">
                    <span className="text-slate-500">الاختبارات</span>
                    <span className="font-bold text-blue-700">{stats.completedQuizzes}</span>
                  </div>
                  <div className="h-px bg-slate-100"></div>
                  <p className="text-xs text-slate-400 leading-relaxed">
                    يستخدم ميزان خوارزميات الذكاء الاصطناعي لتقسيم التفاعيل بناءً على نطق الكلمة (العروض) وليس رسمها الإملائي.
                  </p>
                </div>
              </div>

              <div className="bg-indigo-900 rounded-3xl p-8 text-white shadow-xl shadow-indigo-900/10">
                <h4 className="font-bold mb-4 flex items-center gap-2">
                  <svg xmlns="http://www.w3.org/2000/svg" className="h-5 w-5 text-indigo-400" viewBox="0 0 20 20" fill="currentColor">
                    <path fillRule="evenodd" d="M11.3 1.046A1 1 0 0112 2v5h4a1 1 0 01.82 1.573l-7 10A1 1 0 018 18v-5H4a1 1 0 01-.82-1.573l7-10a1 1 0 011.12-.38z" clipRule="evenodd" />
                  </svg>
                  نصيحة الميزان
                </h4>
                <p className="text-indigo-100 text-sm leading-loose">
                  تذكر أن التنوين في العروض يكتب نوناً ساكنة، وأن الشدة تفك إلى حرفين: أولهما ساكن وثانيهما متحرك.
                </p>
              </div>
            </div>
          </div>
        )}

        {activeView === 'dashboard' && <LearningDashboard stats={stats} />}
        {activeView === 'knowledge' && <KnowledgeBase />}

      </main>

      {/* Decorative Floating Elements */}
      <div className="fixed bottom-10 left-10 opacity-10 pointer-events-none hidden xl:block">
        <div className="text-[200px] font-amiri text-emerald-900 select-none">عروض</div>
      </div>

      <footer className="mt-20 py-10 text-center border-t border-slate-100">
        <div className="flex justify-center gap-6 mb-4">
          <div className="w-10 h-10 bg-slate-200 rounded-full flex items-center justify-center text-slate-500 hover:bg-emerald-600 hover:text-white transition-all cursor-pointer">
            <span className="font-bold">A</span>
          </div>
          <div className="w-10 h-10 bg-slate-200 rounded-full flex items-center justify-center text-slate-500 hover:bg-emerald-600 hover:text-white transition-all cursor-pointer">
            <span className="font-bold">B</span>
          </div>
        </div>
        <p className="text-slate-400 font-medium">ميزان الإيقاع الشعري الذكي © {new Date().getFullYear()}</p>
        <p className="text-[10px] text-slate-300 mt-1 uppercase tracking-widest">Pedagogical Assessment Framework v2.0</p>
      </footer>
    </div>
  );
};

export default App;

import React, { useState, useEffect } from 'react';
import { analyzeVerse } from './services/geminiService';
import { ProsodyAnalysis, HistoryItem, StudentStats } from './types';
import Visualizer from './components/Visualizer';
import AssessmentEngine from './components/AssessmentEngine';
import HistoryPanel from './components/HistoryPanel';
import LearningDashboard from './components/LearningDashboard';
import KnowledgeBase from './components/KnowledgeBase';

type ViewState = 'analyzer' | 'dashboard' | 'knowledge';

const App: React.FC = () => {
  const [activeView, setActiveView] = useState<ViewState>('analyzer');
  const [verse, setVerse] = useState('');
  const [loading, setLoading] = useState(false);
  const [result, setResult] = useState<ProsodyAnalysis | null>(null);
  const [error, setError] = useState<string | null>(null);
  const [showAssessment, setShowAssessment] = useState(false);
  const [history, setHistory] = useState<HistoryItem[]>([]);
  const [showHistory, setShowHistory] = useState(false);
  const [saveStatus, setSaveStatus] = useState<boolean>(false);

  const [stats, setStats] = useState<StudentStats>({
    interactionsCount: 0,
    strengths: [],
    recurringErrors: [],
    completedQuizzes: 0,
    averageScore: 0
  });

  useEffect(() => {
    const savedHistory = localStorage.getItem('mizan_history');
    if (savedHistory) setHistory(JSON.parse(savedHistory));
    const savedStats = localStorage.getItem('mizan_stats');
    if (savedStats) setStats(JSON.parse(savedStats));
  }, []);

  useEffect(() => {
    localStorage.setItem('mizan_history', JSON.stringify(history));
    localStorage.setItem('mizan_stats', JSON.stringify(stats));
  }, [history, stats]);

  const handleAnalyze = async () => {
    if (!verse.trim()) return;
    setLoading(true);
    setError(null);
    setResult(null);
    setShowAssessment(false);
    setSaveStatus(false);
    try {
      const analysis = await analyzeVerse(verse);
      setResult(analysis);

      const newItem: HistoryItem = {
        ...analysis,
        id: Math.random().toString(36).substr(2, 9),
        timestamp: Date.now()
      };
      if (!history.find(h => h.original === analysis.original)) {
        setHistory(prev => [newItem, ...prev].slice(0, 20));
      }

      setStats(prev => ({
        ...prev,
        interactionsCount: prev.interactionsCount + 1
      }));

    } catch (err: any) {
      setError(err.message || 'حدث خطأ في محرك الميزان');
    } finally {
      setLoading(false);
    }
  };

  const handleSaveToLocalStorage = () => {
    if (!result) return;

    const savedVersesKey = 'mizan_saved_verses';
    const existingSaved = localStorage.getItem(savedVersesKey);
    const savedList: HistoryItem[] = existingSaved ? JSON.parse(existingSaved) : [];

    const newItem: HistoryItem = {
      ...result,
      id: Math.random().toString(36).substr(2, 9),
      timestamp: Date.now()
    };

    savedList.push(newItem);
    localStorage.setItem(savedVersesKey, JSON.stringify(savedList));

    setSaveStatus(true);
    setTimeout(() => setSaveStatus(false), 3000);
  };

  const handleSelectHistory = (item: HistoryItem) => {
    setResult(item);
    setVerse(item.original);
    setShowAssessment(false);
    setShowHistory(false);
    setSaveStatus(false);
    setActiveView('analyzer');
    window.scrollTo({ top: 0, behavior: 'smooth' });
  };

  return (
    <div className="min-h-screen pb-20 text-slate-900 bg-[#fcfbf7] font-Tajawal">
      {/* Decorative Top Border */}
      <div className="h-2 bg-gradient-to-l from-emerald-800 via-emerald-600 to-emerald-800 w-full"></div>

      {/* Modern Header */}
      <header className="bg-white py-8 px-6 shadow-sm relative overflow-hidden border-b border-slate-100">
        <div className="max-w-5xl mx-auto flex flex-col md:flex-row items-center justify-between gap-6 relative z-10">
          <div className="flex items-center gap-4">
            <div className="w-16 h-16 bg-emerald-900 rounded-2xl flex items-center justify-center shadow-lg transform -rotate-3">
              <span className="text-3xl font-amiri text-white font-bold">م</span>
            </div>
            <div>
              <h1 className="text-4xl font-amiri font-bold text-emerald-900 tracking-tight">ميزان الذكي</h1>
              <p className="text-slate-500 font-medium">نظام التقطيع الإيقاعي والتقويم التربوي</p>
            </div>
          </div>

          <nav className="flex bg-slate-100 p-1.5 rounded-2xl border border-slate-200 shadow-inner" aria-label="رئيسي">
            <button 
              onClick={() => setActiveView('analyzer')}
              className={`px-6 py-2.5 rounded-xl font-bold transition-all flex items-center gap-2 focus:ring-2 focus:ring-emerald-500 focus:outline-none ${activeView === 'analyzer' ? 'bg-white text-emerald-700 shadow-md' : 'text-slate-500 hover:text-emerald-800'}`}
            >
              <svg xmlns="http://www.w3.org/2000/svg" className="h-5 w-5" viewBox="0 0 20 20" fill="currentColor">
                <path fillRule="evenodd" d="M7 2a1 1 0 00-1 1v1H4a2 2 0 00-2 2v10a2 2 0 002 2h12a2 2 0 002-2V6a2 2 0 00-2-2h-2V3a1 1 0 00-1-1H7zM6 5v1h8V5H6z" clipRule="evenodd" />
              </svg>
              المختبر العروضي
            </button>
            <button 
              onClick={() => setActiveView('dashboard')}
              className={`px-6 py-2.5 rounded-xl font-bold transition-all flex items-center gap-2 focus:ring-2 focus:ring-emerald-500 focus:outline-none ${activeView === 'dashboard' ? 'bg-white text-emerald-700 shadow-md' : 'text-slate-500 hover:text-emerald-800'}`}
            >
              <svg xmlns="http://www.w3.org/2000/svg" className="h-5 w-5" viewBox="0 0 20 20" fill="currentColor">
                <path d="M2 11a1 1 0 011-1h2a1 1 0 011 1v5a1 1 0 01-1 1H3a1 1 0 01-1-1v-5zM8 7a1 1 0 011-1h2a1 1 0 011 1v9a1 1 0 01-1 1H9a1 1 0 01-1-1V7zM14 4a1 1 0 011-1h2a1 1 0 011 1v12a1 1 0 01-1 1h-2a1 1 0 01-1-1V4z" />
              </svg>
              لوحة المهارات
            </button>
            <button 
              onClick={() => setActiveView('knowledge')}
              className={`px-6 py-2.5 rounded-xl font-bold transition-all flex items-center gap-2 focus:ring-2 focus:ring-emerald-500 focus:outline-none ${activeView === 'knowledge' ? 'bg-white text-emerald-700 shadow-md' : 'text-slate-500 hover:text-emerald-800'}`}
            >
              <svg xmlns="http://www.w3.org/2000/svg" className="h-5 w-5" viewBox="0 0 20 20" fill="currentColor">
                <path d="M9 4.804A7.993 7.993 0 002 12a7.993 7.993 0 007 7.196V4.804zM11 4.804v14.392A7.993 7.993 0 0018 12a7.993 7.993 0 00-7-7.196z" />
              </svg>
              موسوعة البحور
            </button>
          </nav>
        </div>
      </header>

      <main className="max-w-5xl mx-auto px-4 mt-12 relative z-10">

        {activeView === 'analyzer' && (
          <div className="grid grid-cols-1 lg:grid-cols-12 gap-8">

            {/* Right Column: Input & Results */}
            <div className="lg:col-span-8 space-y-8">
              <div className="bg-white rounded-3xl shadow-xl shadow-emerald-900/5 p-8 border border-slate-100 relative overflow-hidden">
                <div className="absolute top-0 right-0 w-32 h-32 bg-emerald-50 rounded-full -mr-16 -mt-16 opacity-50"></div>

                <h3 className="text-2xl font-bold text-slate-800 mb-6 flex items-center gap-3">
                  <span className="w-8 h-8 bg-emerald-100 text-emerald-700 rounded-lg flex items-center justify-center text-sm">1</span>
                  المحلل الإيقاعي الذكي
                </h3>

                {showHistory ? (
                  <div className="animate-in fade-in zoom-in-95">
                    <HistoryPanel 
                      history={history} 
                      onSelect={handleSelectHistory} 
                      onDelete={(id) => setHistory(h => h.filter(i => i.id !== id))}
                      onClear={() => setHistory([])}
                    />
                    <button 
                      onClick={() => setShowHistory(false)}
                      className="w-full mt-6 py-3 text-emerald-700 font-bold bg-emerald-50 rounded-xl hover:bg-emerald-100 transition-colors focus:ring-4 focus:ring-emerald-500/20 focus:outline-none"
                    >
                      العودة للمختبر
                    </button>
                  </div>
                ) : (
                  <>
                    <div className="relative group">
                      <textarea
                        id="verse"
                        className="w-full h-40 p-6 text-3xl font-amiri leading-relaxed bg-slate-50 border-2 border-slate-100 rounded-2xl focus:ring-4 focus:ring-emerald-500/10 focus:border-emerald-500 transition-all text-center resize-none shadow-inner outline-none"
                        placeholder="اكتب البيت الشعري هنا للحصول على الوزن والتقطيع..."
                        value={verse}
                        onChange={(e) => setVerse(e.target.value)}
                        disabled={loading}
                      />
                      <div className="absolute bottom-4 right-4 text-xs text-slate-400 font-bold uppercase tracking-widest opacity-0 group-hover:opacity-100 transition-opacity">
                        AI Enabled Analysis
                      </div>
                    </div>

                    <div className="flex gap-4 mt-6">
                      <button
                        onClick={handleAnalyze}
                        disabled={loading || !verse.trim()}
                        className={`flex-1 py-4 text-xl font-bold rounded-2xl shadow-lg transition-all flex items-center justify-center gap-3 focus:ring-4 focus:ring-emerald-500 focus:outline-none
                          ${loading ? 'bg-slate-200 text-slate-400 cursor-not-allowed' : 'bg-emerald-600 hover:bg-emerald-700 text-white hover:-translate-y-1 active:translate-y-0 shadow-emerald-200'}`}
                      >
                        {loading ? (
                          <div className="flex items-center gap-3">
                            <div className="w-6 h-6 border-4 border-slate-300 border-t-emerald-600 rounded-full animate-spin"></div>
                            <span>جاري معالجة الإيقاع...</span>
                          </div>
                        ) : 'بدء التحليل الرقمي'}
                      </button>

                      <button 
                        onClick={() => setShowHistory(true)}
                        className="w-14 h-14 bg-slate-100 text-slate-500 rounded-2xl flex items-center justify-center hover:bg-slate-200 transition-all border border-slate-200 focus:ring-4 focus:ring-slate-300 focus:outline-none"
                        title="سجل التحليلات"
                        aria-label="عرض سجل التحليلات السابقة"
                      >
                        <svg xmlns="http://www.w3.org/2000/svg" className="h-6 w-6" fill="none" viewBox="0 0 24 24" stroke="currentColor">
                          <path strokeLinecap="round" strokeLinejoin="round" strokeWidth={2} d="M12 8v4l3 3m6-3a9 9 0 11-18 0 9 9 0 0118 0z" />
                        </svg>
                      </button>
                    </div>
                  </>
                )}
              </div>

              {error && <div className="p-6 bg-red-50 border-2 border-red-100 rounded-3xl text-red-700 text-center font-bold animate-bounce">{error}</div>}

              {result && (
                <div className="space-y-8 animate-in fade-in slide-in-from-bottom-8 duration-700">
                  {/* Bahr & Assessment Toggle */}
                  <div className="bg-amber-50 rounded-3xl p-8 border border-amber-200 text-center shadow-md relative overflow-hidden group">
                    <div className="absolute top-0 left-0 w-2 h-full bg-amber-400"></div>
                    <span className="text-amber-800 font-bold uppercase tracking-[0.2em] text-xs block mb-2 opacity-60">Result Identified</span>
                    <h2 className="text-5xl font-amiri font-bold text-amber-900 drop-shadow-sm">{result.meterName}</h2>
                    <div className="mt-6 flex flex-wrap justify-center gap-4">
                      <button 
                        onClick={() => setShowAssessment(!showAssessment)}
                        className={`px-8 py-3.5 rounded-2xl font-bold shadow-xl transition-all flex items-center gap-3 transform hover:scale-105 focus:ring-4 focus:ring-indigo-500/50 focus:outline-none
                          ${showAssessment ? 'bg-slate-800 text-white ring-4 ring-slate-100' : 'bg-indigo-600 text-white hover:bg-indigo-700 shadow-indigo-200'}`}
                      >
                        <svg xmlns="http://www.w3.org/2000/svg" className="h-5 w-5" viewBox="0 0 20 20" fill="currentColor">
                          <path d="M10.394 2.827a1 1 0 00-.788 0l-7 3a1 1 0 000 1.848l7 3a1 1 0 00.788 0l7-3a1 1 0 000-1.848l-7-3zM3.94 6L10 8.599 16.06 6 10 3.401 3.94 6z" />
                          <path d="M4.588 9L10 11.318 15.412 9A1 1 0 0117 10.312V14.12a1 1 0 01-.606.919l-5.636 2.416a1 1 0 01-.788 0L4.336 15.04a1 1 0 01-.606-.92V10.312A1 1 0 014.588 9z" />
                        </svg>
                        {showAssessment ? 'إغلاق نافذة الاختبار' : 'بدء تقويم المهارات والمعارف'}
                      </button>

                      <button 
                        onClick={handleSaveToLocalStorage}
                        className={`px-8 py-3.5 rounded-2xl font-bold shadow-xl transition-all flex items-center gap-3 transform hover:scale-105 focus:ring-4 focus:ring-slate-300 focus:outline-none
                          ${saveStatus ? 'bg-emerald-100 text-emerald-800 ring-2 ring-emerald-300' : 'bg-white text-slate-700 hover:bg-slate-50 border border-slate-200'}`}
                      >
                        {saveStatus ? (
                          <>
                            <svg xmlns="http://www.w3.org/2000/svg" className="h-5 w-5 text-emerald-600" viewBox="0 0 20 20" fill="currentColor">
                              <path fillRule="evenodd" d="M16.707 5.293a1 1 0 010 1.414l-8 8a1 1 0 01-1.414 0l-4-4a1 1 0 011.414-1.414L8 12.586l7.293-7.293a1 1 0 011.414 0z" clipRule="evenodd" />
                            </svg>
                            تم الحفظ!
                          </>
                        ) : (
                          <>
                            <svg xmlns="http://www.w3.org/2000/svg" className="h-5 w-5" viewBox="0 0 20 20" fill="currentColor">
                              <path d="M5 4a2 2 0 012-2h6a2 2 0 012 2v14l-5-2.5L5 18V4z" />
                            </svg>
                            حفظ التحليل
                          </>
                        )}
                      </button>
                    </div>
                  </div>

                  {showAssessment && <AssessmentEngine analysis={result} />}

                  <div className="grid grid-cols-1 md:grid-cols-2 gap-8">
                    <div className="bg-white rounded-3xl p-8 shadow-sm border border-slate-100 hover:shadow-md transition-shadow">
                      <h4 className="text-sm font-bold text-slate-400 mb-6 uppercase tracking-widest border-b pb-2">النص المشكول</h4>
                      <p className="text-3xl font-amiri leading-relaxed text-slate-800 text-center">{result.diacritized}</p>
                    </div>
                    <div className="bg-white rounded-3xl p-8 shadow-sm border border-slate-100 hover:shadow-md transition-shadow">
                      <h4 className="text-sm font-bold text-slate-400 mb-6 uppercase tracking-widest border-b pb-2">الكتابة العروضية</h4>
                      <p className="text-3xl font-amiri leading-relaxed text-emerald-800 text-center">{result.prosodicWriting}</p>
                    </div>
                  </div>

                  <div className="bg-white rounded-3xl p-8 shadow-sm border border-slate-100">
                    <h4 className="text-sm font-bold text-slate-400 mb-8 uppercase tracking-widest border-b pb-2 text-center">التوقيع الإيقاعي الرقمي</h4>
                    <Visualizer symbols={result.symbols} />
                  </div>

                  <div className="bg-white rounded-3xl p-8 shadow-sm border border-slate-100">
                    <h4 className="text-sm font-bold text-slate-400 mb-10 uppercase tracking-widest border-b pb-2 text-center">مصفوفة التفاعيل</h4>
                    <div className="flex flex-wrap gap-6 justify-center">
                      {result.tafilat.map((taf, idx) => (
                        <div key={idx} className="group relative flex flex-col items-center p-6 bg-slate-50 rounded-2xl border-2 border-slate-100 transition-all hover:bg-emerald-50 hover:border-emerald-200 hover:-translate-y-2">
                          <div className="absolute -top-14 opacity-0 group-hover:opacity-100 transition-all bg-slate-900 text-white text-xs px-4 py-2 rounded-xl whitespace-nowrap z-30 pointer-events-none shadow-xl border border-white/10 text-center">
                            <p className="font-bold mb-1">{taf.text}</p>
                            <p className="font-mono opacity-60" dir="ltr">{taf.pattern}</p>
                            <div className="absolute top-full left-1/2 -translate-x-1/2 border-6 border-transparent border-t-slate-900"></div>
                          </div>
                          <span className="text-3xl font-amiri text-slate-800 mb-3">{taf.text}</span>
                          <span className="text-sm font-mono font-bold text-slate-400 bg-white px-3 py-1 rounded-full border border-slate-200 shadow-sm" dir="ltr">{taf.pattern}</span>
                        </div>
                      ))}
                    </div>
                  </div>

                  {result.explanation && (
                    <div className="bg-emerald-900 rounded-3xl p-10 text-white shadow-2xl relative overflow-hidden">
                      <div className="absolute bottom-0 right-0 w-64 h-64 bg-emerald-800 rounded-full -mb-32 -mr-32 opacity-20"></div>
                      <h3 className="text-xl font-bold mb-6 flex items-center gap-3">
                        <svg xmlns="http://www.w3.org/2000/svg" className="h-6 w-6 text-emerald-400" viewBox="0 0 20 20" fill="currentColor">
                          <path fillRule="evenodd" d="M18 10a8 8 0 11-16 0 8 8 0 0116 0zm-7-4a1 1 0 11-2 0 1 1 0 012 0zM9 9a1 1 0 000 2v3a1 1 0 001 1h1a1 1 0 100-2v-3a1 1 0 00-1-1H9z" clipRule="evenodd" />
                        </svg>
                        التعليق البيداغوجي
                      </h3>
                      <p className="leading-loose text-emerald-50 text-xl font-medium font-Tajawal italic">"{result.explanation}"</p>
                    </div>
                  )}
                </div>
              )}
            </div>

            {/* Left Column: Quick Stats / Tips */}
            <div className="lg:col-span-4 space-y-8">
              <div className="bg-white rounded-3xl p-8 shadow-sm border border-slate-100">
                <h4 className="font-bold text-slate-800 mb-6 flex items-center gap-2">
                  <span className="w-2 h-6 bg-emerald-600 rounded-full"></span>
                  نظرة سريعة
                </h4>
                <div className="space-y-6">
                  <div className="flex items-center justify-between">
                    <span className="text-slate-500">التحليلات اليوم</span>
                    <span className="font-bold text-emerald-700">{stats.interactionsCount}</span>
                  </div>
                  <div className="flex items-center justify-between">
                    <span className="text-slate-500">الاختبارات</span>
                    <span className="font-bold text-blue-700">{stats.completedQuizzes}</span>
                  </div>
                  <div className="h-px bg-slate-100"></div>
                  <p className="text-xs text-slate-400 leading-relaxed">
                    يستخدم ميزان خوارزميات الذكاء الاصطناعي لتقسيم التفاعيل بناءً على نطق الكلمة (العروض) وليس رسمها الإملائي.
                  </p>
                </div>
              </div>

              <div className="bg-indigo-900 rounded-3xl p-8 text-white shadow-xl shadow-indigo-900/10">
                <h4 className="font-bold mb-4 flex items-center gap-2">
                  <svg xmlns="http://www.w3.org/2000/svg" className="h-5 w-5 text-indigo-400" viewBox="0 0 20 20" fill="currentColor">
                    <path fillRule="evenodd" d="M11.3 1.046A1 1 0 0112 2v5h4a1 1 0 01.82 1.573l-7 10A1 1 0 018 18v-5H4a1 1 0 01-.82-1.573l7-10a1 1 0 011.12-.38z" clipRule="evenodd" />
                  </svg>
                  نصيحة الميزان
                </h4>
                <p className="text-indigo-100 text-sm leading-loose">
                  تذكر أن التنوين في العروض يكتب نوناً ساكنة، وأن الشدة تفك إلى حرفين: أولهما ساكن وثانيهما متحرك.
                </p>
              </div>
            </div>
          </div>
        )}

        {activeView === 'dashboard' && <LearningDashboard stats={stats} />}
        {activeView === 'knowledge' && <KnowledgeBase />}

      </main>

      {/* Decorative Floating Elements */}
      <div className="fixed bottom-10 left-10 opacity-10 pointer-events-none hidden xl:block">
        <div className="text-[200px] font-amiri text-emerald-900 select-none">عروض</div>
      </div>

      <footer className="mt-20 py-10 text-center border-t border-slate-100">
        <div className="flex justify-center gap-6 mb-4">
          <div className="w-10 h-10 bg-slate-200 rounded-full flex items-center justify-center text-slate-500 hover:bg-emerald-600 hover:text-white transition-all cursor-pointer">
            <span className="font-bold">A</span>
          </div>
          <div className="w-10 h-10 bg-slate-200 rounded-full flex items-center justify-center text-slate-500 hover:bg-emerald-600 hover:text-white transition-all cursor-pointer">
            <span className="font-bold">B</span>
          </div>
        </div>
        <p className="text-slate-400 font-medium">ميزان الإيقاع الشعري الذكي © {new Date().getFullYear()}</p>
        <p className="text-[10px] text-slate-300 mt-1 uppercase tracking-widest">Pedagogical Assessment Framework v2.0</p>
      </footer>
    </div>
  );
};

export default App;

import React, { useState, useEffect } from 'react';
import { analyzeVerse } from './services/geminiService';
import { ProsodyAnalysis, HistoryItem, StudentStats } from './types';
import Visualizer from './components/Visualizer';
import AssessmentEngine from './components/AssessmentEngine';
import HistoryPanel from './components/HistoryPanel';
import LearningDashboard from './components/LearningDashboard';
import KnowledgeBase from './components/KnowledgeBase';

type ViewState = 'analyzer' | 'dashboard' | 'knowledge';

const App: React.FC = () => {
  const [activeView, setActiveView] = useState<ViewState>('analyzer');
  const [verse, setVerse] = useState('');
  const [loading, setLoading] = useState(false);
  const [result, setResult] = useState<ProsodyAnalysis | null>(null);
  const [error, setError] = useState<string | null>(null);
  const [showAssessment, setShowAssessment] = useState(false);
  const [history, setHistory] = useState<HistoryItem[]>([]);
  const [showHistory, setShowHistory] = useState(false);
  const [saveStatus, setSaveStatus] = useState<boolean>(false);

  const [stats, setStats] = useState<StudentStats>({
    interactionsCount: 0,
    strengths: [],
    recurringErrors: [],
    completedQuizzes: 0,
    averageScore: 0
  });

  useEffect(() => {
    const savedHistory = localStorage.getItem('mizan_history');
    if (savedHistory) setHistory(JSON.parse(savedHistory));
    const savedStats = localStorage.getItem('mizan_stats');
    if (savedStats) setStats(JSON.parse(savedStats));
  }, []);

  useEffect(() => {
    localStorage.setItem('mizan_history', JSON.stringify(history));
    localStorage.setItem('mizan_stats', JSON.stringify(stats));
  }, [history, stats]);

  const handleAnalyze = async () => {
    if (!verse.trim()) return;
    setLoading(true);
    setError(null);
    setResult(null);
    setShowAssessment(false);
    setSaveStatus(false);
    try {
      const analysis = await analyzeVerse(verse);
      setResult(analysis);

      const newItem: HistoryItem = {
        ...analysis,
        id: Math.random().toString(36).substr(2, 9),
        timestamp: Date.now()
      };
      if (!history.find(h => h.original === analysis.original)) {
        setHistory(prev => [newItem, ...prev].slice(0, 20));
      }

      setStats(prev => ({
        ...prev,
        interactionsCount: prev.interactionsCount + 1
      }));

    } catch (err: any) {
      setError(err.message || 'حدث خطأ في محرك الميزان');
    } finally {
      setLoading(false);
    }
  };

  const handleSaveToLocalStorage = () => {
    if (!result) return;

    const savedVersesKey = 'mizan_saved_verses';
    const existingSaved = localStorage.getItem(savedVersesKey);
    const savedList: HistoryItem[] = existingSaved ? JSON.parse(existingSaved) : [];

    const newItem: HistoryItem = {
      ...result,
      id: Math.random().toString(36).substr(2, 9),
      timestamp: Date.now()
    };

    savedList.push(newItem);
    localStorage.setItem(savedVersesKey, JSON.stringify(savedList));

    setSaveStatus(true);
    setTimeout(() => setSaveStatus(false), 3000);
  };

  const handleSelectHistory = (item: HistoryItem) => {
    setResult(item);
    setVerse(item.original);
    setShowAssessment(false);
    setShowHistory(false);
    setSaveStatus(false);
    setActiveView('analyzer');
    window.scrollTo({ top: 0, behavior: 'smooth' });
  };

  return (
    <div className="min-h-screen pb-20 text-slate-900 bg-[#fcfbf7] font-Tajawal">
      {/* Decorative Top Border */}
      <div className="h-2 bg-gradient-to-l from-emerald-800 via-emerald-600 to-emerald-800 w-full"></div>

      {/* Modern Header */}
      <header className="bg-white py-8 px-6 shadow-sm relative overflow-hidden border-b border-slate-100">
        <div className="max-w-5xl mx-auto flex flex-col md:flex-row items-center justify-between gap-6 relative z-10">
          <div className="flex items-center gap-4">
            <div className="w-16 h-16 bg-emerald-900 rounded-2xl flex items-center justify-center shadow-lg transform -rotate-3">
              <span className="text-3xl font-amiri text-white font-bold">م</span>
            </div>
            <div>
              <h1 className="text-4xl font-amiri font-bold text-emerald-900 tracking-tight">ميزان الذكي</h1>
              <p className="text-slate-500 font-medium">نظام التقطيع الإيقاعي والتقويم التربوي</p>
            </div>
          </div>

          <nav className="flex bg-slate-100 p-1.5 rounded-2xl border border-slate-200 shadow-inner" aria-label="رئيسي">
            <button 
              onClick={() => setActiveView('analyzer')}
              className={`px-6 py-2.5 rounded-xl font-bold transition-all flex items-center gap-2 focus:ring-2 focus:ring-emerald-500 focus:outline-none ${activeView === 'analyzer' ? 'bg-white text-emerald-700 shadow-md' : 'text-slate-500 hover:text-emerald-800'}`}
            >
              <svg xmlns="http://www.w3.org/2000/svg" className="h-5 w-5" viewBox="0 0 20 20" fill="currentColor">
                <path fillRule="evenodd" d="M7 2a1 1 0 00-1 1v1H4a2 2 0 00-2 2v10a2 2 0 002 2h12a2 2 0 002-2V6a2 2 0 00-2-2h-2V3a1 1 0 00-1-1H7zM6 5v1h8V5H6z" clipRule="evenodd" />
              </svg>
              المختبر العروضي
            </button>
            <button 
              onClick={() => setActiveView('dashboard')}
              className={`px-6 py-2.5 rounded-xl font-bold transition-all flex items-center gap-2 focus:ring-2 focus:ring-emerald-500 focus:outline-none ${activeView === 'dashboard' ? 'bg-white text-emerald-700 shadow-md' : 'text-slate-500 hover:text-emerald-800'}`}
            >
              <svg xmlns="http://www.w3.org/2000/svg" className="h-5 w-5" viewBox="0 0 20 20" fill="currentColor">
                <path d="M2 11a1 1 0 011-1h2a1 1 0 011 1v5a1 1 0 01-1 1H3a1 1 0 01-1-1v-5zM8 7a1 1 0 011-1h2a1 1 0 011 1v9a1 1 0 01-1 1H9a1 1 0 01-1-1V7zM14 4a1 1 0 011-1h2a1 1 0 011 1v12a1 1 0 01-1 1h-2a1 1 0 01-1-1V4z" />
              </svg>
              لوحة المهارات
            </button>
            <button 
              onClick={() => setActiveView('knowledge')}
              className={`px-6 py-2.5 rounded-xl font-bold transition-all flex items-center gap-2 focus:ring-2 focus:ring-emerald-500 focus:outline-none ${activeView === 'knowledge' ? 'bg-white text-emerald-700 shadow-md' : 'text-slate-500 hover:text-emerald-800'}`}
            >
              <svg xmlns="http://www.w3.org/2000/svg" className="h-5 w-5" viewBox="0 0 20 20" fill="currentColor">
                <path d="M9 4.804A7.993 7.993 0 002 12a7.993 7.993 0 007 7.196V4.804zM11 4.804v14.392A7.993 7.993 0 0018 12a7.993 7.993 0 00-7-7.196z" />
              </svg>
              موسوعة البحور
            </button>
          </nav>
        </div>
      </header>

      <main className="max-w-5xl mx-auto px-4 mt-12 relative z-10">

        {activeView === 'analyzer' && (
          <div className="grid grid-cols-1 lg:grid-cols-12 gap-8">

            {/* Right Column: Input & Results */}
            <div className="lg:col-span-8 space-y-8">
              <div className="bg-white rounded-3xl shadow-xl shadow-emerald-900/5 p-8 border border-slate-100 relative overflow-hidden">
                <div className="absolute top-0 right-0 w-32 h-32 bg-emerald-50 rounded-full -mr-16 -mt-16 opacity-50"></div>

                <h3 className="text-2xl font-bold text-slate-800 mb-6 flex items-center gap-3">
                  <span className="w-8 h-8 bg-emerald-100 text-emerald-700 rounded-lg flex items-center justify-center text-sm">1</span>
                  المحلل الإيقاعي الذكي
                </h3>

                {showHistory ? (
                  <div className="animate-in fade-in zoom-in-95">
                    <HistoryPanel 
                      history={history} 
                      onSelect={handleSelectHistory} 
                      onDelete={(id) => setHistory(h => h.filter(i => i.id !== id))}
                      onClear={() => setHistory([])}
                    />
                    <button 
                      onClick={() => setShowHistory(false)}
                      className="w-full mt-6 py-3 text-emerald-700 font-bold bg-emerald-50 rounded-xl hover:bg-emerald-100 transition-colors focus:ring-4 focus:ring-emerald-500/20 focus:outline-none"
                    >
                      العودة للمختبر
                    </button>
                  </div>
                ) : (
                  <>
                    <div className="relative group">
                      <textarea
                        id="verse"
                        className="w-full h-40 p-6 text-3xl font-amiri leading-relaxed bg-slate-50 border-2 border-slate-100 rounded-2xl focus:ring-4 focus:ring-emerald-500/10 focus:border-emerald-500 transition-all text-center resize-none shadow-inner outline-none"
                        placeholder="اكتب البيت الشعري هنا للحصول على الوزن والتقطيع..."
                        value={verse}
                        onChange={(e) => setVerse(e.target.value)}
                        disabled={loading}
                      />
                      <div className="absolute bottom-4 right-4 text-xs text-slate-400 font-bold uppercase tracking-widest opacity-0 group-hover:opacity-100 transition-opacity">
                        AI Enabled Analysis
                      </div>
                    </div>

                    <div className="flex gap-4 mt-6">
                      <button
                        onClick={handleAnalyze}
                        disabled={loading || !verse.trim()}
                        className={`flex-1 py-4 text-xl font-bold rounded-2xl shadow-lg transition-all flex items-center justify-center gap-3 focus:ring-4 focus:ring-emerald-500 focus:outline-none
                          ${loading ? 'bg-slate-200 text-slate-400 cursor-not-allowed' : 'bg-emerald-600 hover:bg-emerald-700 text-white hover:-translate-y-1 active:translate-y-0 shadow-emerald-200'}`}
                      >
                        {loading ? (
                          <div className="flex items-center gap-3">
                            <div className="w-6 h-6 border-4 border-slate-300 border-t-emerald-600 rounded-full animate-spin"></div>
                            <span>جاري معالجة الإيقاع...</span>
                          </div>
                        ) : 'بدء التحليل الرقمي'}
                      </button>

                      <button 
                        onClick={() => setShowHistory(true)}
                        className="w-14 h-14 bg-slate-100 text-slate-500 rounded-2xl flex items-center justify-center hover:bg-slate-200 transition-all border border-slate-200 focus:ring-4 focus:ring-slate-300 focus:outline-none"
                        title="سجل التحليلات"
                        aria-label="عرض سجل التحليلات السابقة"
                      >
                        <svg xmlns="http://www.w3.org/2000/svg" className="h-6 w-6" fill="none" viewBox="0 0 24 24" stroke="currentColor">
                          <path strokeLinecap="round" strokeLinejoin="round" strokeWidth={2} d="M12 8v4l3 3m6-3a9 9 0 11-18 0 9 9 0 0118 0z" />
                        </svg>
                      </button>
                    </div>
                  </>
                )}
              </div>

              {error && <div className="p-6 bg-red-50 border-2 border-red-100 rounded-3xl text-red-700 text-center font-bold animate-bounce">{error}</div>}

              {result && (
                <div className="space-y-8 animate-in fade-in slide-in-from-bottom-8 duration-700">
                  {/* Bahr & Assessment Toggle */}
                  <div className="bg-amber-50 rounded-3xl p-8 border border-amber-200 text-center shadow-md relative overflow-hidden group">
                    <div className="absolute top-0 left-0 w-2 h-full bg-amber-400"></div>
                    <span className="text-amber-800 font-bold uppercase tracking-[0.2em] text-xs block mb-2 opacity-60">Result Identified</span>
                    <h2 className="text-5xl font-amiri font-bold text-amber-900 drop-shadow-sm">{result.meterName}</h2>
                    <div className="mt-6 flex flex-wrap justify-center gap-4">
                      <button 
                        onClick={() => setShowAssessment(!showAssessment)}
                        className={`px-8 py-3.5 rounded-2xl font-bold shadow-xl transition-all flex items-center gap-3 transform hover:scale-105 focus:ring-4 focus:ring-indigo-500/50 focus:outline-none
                          ${showAssessment ? 'bg-slate-800 text-white ring-4 ring-slate-100' : 'bg-indigo-600 text-white hover:bg-indigo-700 shadow-indigo-200'}`}
                      >
                        <svg xmlns="http://www.w3.org/2000/svg" className="h-5 w-5" viewBox="0 0 20 20" fill="currentColor">
                          <path d="M10.394 2.827a1 1 0 00-.788 0l-7 3a1 1 0 000 1.848l7 3a1 1 0 00.788 0l7-3a1 1 0 000-1.848l-7-3zM3.94 6L10 8.599 16.06 6 10 3.401 3.94 6z" />
