          </h3>
          {stats.recurringErrors.length > 0 ? (
            <div className="space-y-6">
              {stats.recurringErrors.map((error, idx) => (
                <div key={idx} className="group">
                  <div className="flex items-center justify-between mb-2">
                    <span className="font-amiri text-2xl font-bold text-slate-700">{error.meterName}</span>
                    <span className="text-xs font-bold text-red-500 uppercase tracking-tighter">{error.errorCount} تعثر إيقاعي</span>
                  </div>
                  <div className="h-2 w-full bg-slate-50 rounded-full overflow-hidden">
                    <div 
                      className="h-full bg-red-400 transition-all duration-1000 group-hover:bg-red-500" 
                      style={{ width: `${Math.min(100, (error.errorCount / 5) * 100)}%` }}
                    ></div>
                  </div>
                  <p className="text-[10px] text-slate-400 mt-1">تلميح: راجع قاعدة الزحافات في بحر {error.meterName}</p>
                </div>
