            >
              <svg xmlns="http://www.w3.org/2000/svg" className="h-5 w-5" viewBox="0 0 20 20" fill="currentColor">
                <path fillRule="evenodd" d="M7 2a1 1 0 00-1 1v1H4a2 2 0 00-2 2v10a2 2 0 002 2h12a2 2 0 002-2V6a2 2 0 00-2-2h-2V3a1 1 0 00-1-1H7zM6 5v1h8V5H6z" clipRule="evenodd" />
              </svg>
              المختبر العروضي
            </button>
            <button 
              onClick={() => setActiveView('dashboard')}
              className={`px-6 py-2.5 rounded-xl font-bold transition-all flex items-center gap-2 focus:ring-2 focus:ring-emerald-500 focus:outline-none ${activeView === 'dashboard' ? 'bg-white text-emerald-700 shadow-md' : 'text-slate-500 hover:text-emerald-800'}`}
            >
              <svg xmlns="http://www.w3.org/2000/svg" className="h-5 w-5" viewBox="0 0 20 20" fill="currentColor">
                <path d="M2 11a1 1 0 011-1h2a1 1 0 011 1v5a1 1 0 01-1 1H3a1 1 0 01-1-1v-5zM8 7a1 1 0 011-1h2a1 1 0 011 1v9a1 1 0 01-1 1H9a1 1 0 01-1-1V7zM14 4a1 1 0 011-1h2a1 1 0 011 1v12a1 1 0 01-1 1h-2a1 1 0 01-1-1V4z" />
              </svg>
