      </main>

      <footer className="mt-20 py-10 text-center border-t border-slate-100">
        <p className="text-slate-400 font-medium">ميزان الإيقاع الشعري الذكي © {new Date().getFullYear()}</p>
        <p className="text-[10px] text-slate-300 mt-1 uppercase tracking-widest">Pedagogical Assessment Framework v2.0</p>
      </footer>
